1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // === Simplest cases ===
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // === Base premiums per item type ===
15	  it("newcomer plain sword → 115 G (100 base + 10 first insurance + 5 fee)", () => {
16	    const result = runScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [
19	        {
20	          op: "quote",
21	          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
22	        },
23	      ],
24	    });
25	    expect(result).toEqual({ results: [{ premium: 115 }] });
26	  });
27	  it("newcomer plain amulet → 71 G (60 base + 6 first ins + 5 fee)", () => {
28	    const result = runScenario({
29	      customer: { yearsWithMHPCO: 0 },
30	      steps: [
31	        {
32	          op: "quote",
33	          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
34	        },
35	      ],
36	    });
37	    expect(result).toEqual({ results: [{ premium: 71 }] });
38	  });
39	  it("newcomer plain staff → 93 G (80 base + 8 first ins + 5 fee)", () => {
40	    const result = runScenario({
41	      customer: { yearsWithMHPCO: 0 },
42	      steps: [
43	        {
44	          op: "quote",
45	          items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }],
46	        },
47	      ],
48	    });
49	    expect(result).toEqual({ results: [{ premium: 93 }] });
50	  });
51	  it.todo("single plain potion → 45 G (40 base + 5 fee)");
52	
53	  // === Components and blocks ===
54	  it.todo("single rune → 30 G (25 base + 5 fee)");
55	  it.todo("2 runes → 55 G base premium (50 + 5 fee)");
56	  it.todo("3 runes → 65 G (block of 3 = 60 G base + 5 fee)");
57	  it.todo("4 runes → 105 G (no block; 4×25 = 100 + 5 fee)");
58	  it.todo("7 runes → 180 G (175 base + 5 fee)");
59	  it.todo("2 runes + 1 moonstone → 80 G (75 base + 5 fee, no block: different types)");
60	  it.todo("3 runes + 3 moonstones → 125 G (two separate blocks: 60+60 = 120 + 5 fee)");
61	
62	  // === Item-specific modifiers ===
63	  it.todo("cursed sword → 100 base + 50 curse + 5 fee = 155 G");
64	  it.todo("highly enchanted sword (enchantment 5) → 100 + 30 + 5 = 135 G");
65	  it.todo("sword with enchantment 4 → no high-enchantment surcharge, 105 G");
66	  it.todo("sword with enchantment 5 AND cursed → both surcharges apply (100 + 50 + 30 + 5 = 185 G)");
67	
68	  // === Customer-wide modifiers ===
69	  it.todo("customer with exactly 2 years → loyalty discount applies (sword: 100 - 20 + 10 first + 5 = 95 G)");
70	  it.todo("first insurance → 10% initial assessment surcharge (sword: 100 + 10 + 5 = 115 G for newcomer)");
71	  it.todo("follow-up contract → 15% discount on each contract after first");
72	
73	  // === Modifier scope on multi-item policies ===
74	  it.todo("cursed sword + plain amulet → 100+60 = 160 base; curse adds 50 (on sword only); 160+50+10(first)+5 = 225 G");
75	
76	  // === Rounding in MHPCO favor ===
77	  it.todo("premium calculation yielding 197.5 → 198 G (rounded up)");
78	  it.todo("payout calculation yielding 350.5 → 350 G (rounded down)");
79	
80	  // === Integration examples ===
81	  it.todo("newcomer with cursed sword (steel, ench 3), 0 years → 165 G");
82	  it.todo("long-standing customer's second contract: cursed sword ench 7, 3 years → 160 G");
83	  it.todo("first insurance surcharge applies per item even for follow-up contract");
84	
85	  // === Claim - basic ===
86	  it.todo("standard sword damage 500 → payout 400 (full minus 100 deductible)");
87	  it.todo("damage to rune (250 G value), damage 200 → payout 100");
88	  it.todo("high enchantment item (ench 8), damage 1000 → 50% then deductible = 400");
89	  it.todo("dragon material sword full reimbursement, damage 800, ench 5 → 700");
90	  it.todo("dragon material + high ench (ench 9), damage 1000 → 50% wins, then deductible = 400");
91	  it.todo("dragon-material sword ench exactly 8 damage 1000 → 400 (high-ench applies first)");
92	  it.todo("steel sword ench 9 damage 1000 → 50% then -100 = 400");
93	
94	  // === Deductible per damage event ===
95	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");
96	
97	  // === Multiple items of same type ===
98	  it.todo("policy covers two swords → insurance sum 2000, cap 4000");
99	  it.todo("two swords both damaged → each treated separately with own deductible");
100	  it.todo("damages contain more entries of a type than insured → claim rejected (CLI non-zero)");
101	
102	  // === Cap exhaustion ===
103	  it.todo("sword + amulet policy → insurance sum 1600, cap 3200");
104	  it.todo("cursed sword (premium modifiers don't affect cap) → cap based on unmodified insurance value 2000");
105	  it.todo("sword + 3 runes block → insurance sum 1750 (block doesn't affect insurance sum)");
106	  it.todo("sword cap 2000, two claims 1500 each → first 1400, second capped to 600");
107	  it.todo("remainingCap reaches 0 after exhausting cap");
108	
109	  // === Edge cases / errors ===
110	  it.todo("quote with unknown item type → CLI non-zero exit, error to stderr");
111	  it.todo("claim references item not in policy → CLI non-zero exit");
112	  it.todo("claim with negative damage amount → CLI non-zero exit");
113	
114	  // === CLI / scenario integration ===
115	  it.todo("full scenario with quote then claim returns results in order");
116	});
