1	type Item = { type: string };
2	type Step = { op: "quote"; items: Array<Item> };
3	type Scenario = {
4	  customer: { yearsWithMHPCO: number };
5	  steps: Array<Step>;
6	};
7	type QuoteResult = { premium: number };
8	
9	const PROCESSING_FEE = 5;
10	
11	// Per-item-type quoted premium (base + first-insurance surcharge, before fee).
12	// Hardcoded to the values exercised by current tests; will be derived as
13	// more rules are introduced.
14	const ITEM_PREMIUM_BEFORE_FEE: Record<string, number> = {
15	  sword: 110,
16	  amulet: 66,
17	  staff: 88,
18	};
19	
20	const quoteItem = (item: Item): number => ITEM_PREMIUM_BEFORE_FEE[item.type];
21	
22	const quoteStep = (step: Step): QuoteResult => {
23	  const itemsTotal = step.items.reduce((sum, item) => sum + quoteItem(item), 0);
24	  return { premium: itemsTotal + PROCESSING_FEE };
25	};
26	
27	export const runScenario = (scenario: Scenario): { results: Array<QuoteResult> } => {
28	  return { results: scenario.steps.map(quoteStep) };
29	};
